export const module = {
  add: (a, b) => a + b,
  multiply: (a, b) => a * b
};
import { module } from './math';

package utils.module;
public class Math {
    public static int add(int a, int b) {
        return a + b;
    }
}

CREATE MODULE math_module AS
BEGIN
    CREATE FUNCTION add(a INT, b INT) RETURNS INT
    AS SELECT a + b;
END;
